{
  "parameters": "z.object({
  x: z.number().describe("Target X coordinate"),
  z: z.number().describe("Target Z coordinate"),
  y: z.number().optional().describe("Target Y coordinate; if omitted, the bot moves to the X/Z position at any height"),
  radiusBlocks: z.number().default(2).describe("Distance from the target at which the move is considered successful"),
  timeoutMs: z.number().default(60000).describe("Maximum active time allowed for the move in milliseconds")
})",
  "executionArgs": {
    "x": 0,
    "z": 0,
    "radiusBlocks": 3,
    "timeoutMs": 60000
  },
  "code": "if (!bot.entity || bot.health <= 0) {
  return '<UNSAFE>: Cannot move because the bot is not alive.';
}

const targetX = args.x;
const targetZ = args.z;
const targetY = args.y;
const radius = args.radiusBlocks;
const pollMs = 100;

startBackgroundSkill(bot, 'move_to_coordinate', async function (token) {
  const movements = new Movements(bot);
  movements.canDig = false;
  bot.pathfinder.setMovements(movements);

  let goal;
  if (typeof targetY === 'number') {
    goal = new goals.GoalNear(targetX, targetY, targetZ, radius);
  } else {
    goal = new goals.GoalXZ(targetX, targetZ, radius);
  }

  try {
    if (!await waitUntilWorldActive(bot, token, pollMs)) return;
    bot.pathfinder.setGoal(goal);

    const startTime = Date.now();
    let activeElapsed = 0;

    while (canContinueBotAction(bot, token)) {
      const startWait = Date.now();
      if (!await waitForActiveMs(bot, token, pollMs, pollMs)) break;
      activeElapsed += (Date.now() - startWait);

      if (activeElapsed > args.timeoutMs) break;

      const pos = bot.entity.position;
      if (typeof targetY === 'number') {
        if (pos.distanceTo(new Vec3(targetX, targetY, targetZ)) <= radius) break;
      } else {
        const dx = pos.x - targetX;
        const dz = pos.z - targetZ;
        if (Math.sqrt(dx * dx + dz * dz) <= radius) break;
      }

      if (!bot.pathfinder.isMoving() && !bot.pathfinder.isThinking()) {
        break;
      }
    }
  } finally {
    bot.pathfinder.setGoal(null);
    bot.pathfinder.stop();
  }
});

return '<STARTED>: Moving towards ' + targetX + ', ' + (targetY !== undefined ? targetY : 'any') + ', ' + targetZ + ' with radius ' + radius + '.';
"
}

{
  "parameters": "z.object({ slot: z.number().int().describe("The inventory slot index of the armor item to equip (e.g., 39 for a chestplate in initial survival inventory)"), destination: z.enum(["head", "torso", "legs", "feet"]).optional().describe("Specific armor slot to use. If omitted, the bot will attempt to infer it from the item name.") })",
  "executionArgs": {
    "slot": 39,
    "destination": "torso"
  },
  "code": "if (!bot.entity || bot.health <= 0) {
  return '<UNSAFE>: Cannot equip armor because the bot is not alive.';
}
const slotIndex = parseInt(args.slot, 10);
if (isNaN(slotIndex) || slotIndex < 0) {
  return '<INVALID>: Provided slot index ' + args.slot + ' is not valid.';
}
const item = bot.inventory.slots[slotIndex];
if (!item) {
  return '<NO ITEM>: No item found in inventory slot ' + slotIndex + '.';
}
let targetDest = args.destination;
if (!targetDest) {
  const name = item.name.toLowerCase();
  if (name.includes('helmet') || name.includes('cap') || name.includes('skull') || name.includes('head') || name.includes('shell')) {
    targetDest = 'head';
  } else if (name.includes('chestplate') || name.includes('tunic') || name.includes('elytra')) {
    targetDest = 'torso';
  } else if (name.includes('leggings') || name.includes('pants')) {
    targetDest = 'legs';
  } else if (name.includes('boots')) {
    targetDest = 'feet';
  } else {
    return '<INVALID>: Item ' + item.name + ' in slot ' + slotIndex + ' does not appear to be a piece of armor.';
  }
}
try {
  await bot.equip(item, targetDest);
  return '<DONE>: Equipped ' + (item.displayName || item.name) + ' to ' + targetDest + '.';
} catch (err) {
  return '<INVALID>: Failed to equip item: ' + err.message;
}"
}

{
  "parameters": "z.object({ count: z.number().int().min(1).max(10).default(1).describe("Maximum number of bread pieces to consume."), stopIfFull: z.boolean().default(true).describe("Whether to stop eating once the food bar reaches 20.") })",
  "executionArgs": {
    "count": 1,
    "stopIfFull": true
  },
  "code": "const findBread = function () {
  return bot.inventory.items().find(function (item) {
    return item.name === 'bread' || (item.displayName && item.displayName.toLowerCase().includes('bread'));
  });
};
if (!bot.entity || bot.health <= 0) {
  return '<UNSAFE>: Cannot eat because the bot is not alive.';
}
const initialBread = findBread();
if (!initialBread) {
  return '<NO ITEM>: Could not find bread in inventory.';
}
if (args.stopIfFull && bot.food >= 20) {
  return '<STOPPED>: Food level is already full.';
}
startBackgroundSkill(bot, 'eat_bread', async function (token) {
  let usingItem = false;
  const pollMs = 50;
  const eatDurationMs = 1700;
  try {
    for (let i = 0; i < args.count; i++) {
      if (!canContinueBotAction(bot, token)) return;
      if (args.stopIfFull && bot.food >= 20) return;
      const bread = findBread();
      if (!bread) return;
      if (!await waitUntilWorldActive(bot, token, pollMs)) return;
      await bot.equip(bread, 'hand');
      if (!canContinueBotAction(bot, token)) return;
      bot.activateItem();
      usingItem = true;
      const finished = await waitForActiveMs(bot, token, eatDurationMs, pollMs);
      bot.deactivateItem();
      usingItem = false;
      if (!finished) return;
      if (!await waitForActiveMs(bot, token, 200, pollMs)) return;
    }
  } finally {
    if (usingItem) {
      bot.deactivateItem();
    }
  }
});
return '<STARTED>: Commencing eating bread. Number of pieces: ' + args.count + '.';"
}
